import{_ as t,c as e,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Приложение: Технический справочник | Antigravity-Manager","description":"Технические справочные материалы Antigravity Tools: шпаргалка по API-эндпоинтам, структура хранения данных и описание границ функциональности. Быстрый поиск ключевой информации.","frontmatter":{"title":"Приложение: Технический справочник | Antigravity-Manager","sidebarTitle":"Технический словарь","subtitle":"Приложение: Технический справочник","description":"Технические справочные материалы Antigravity Tools: шпаргалка по API-эндпоинтам, структура хранения данных и описание границ функциональности. Быстрый поиск ключевой информации.","order":500},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/appendix/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/appendix/index.md"}'),n={name:"ru/lbjlaq/Antigravity-Manager/appendix/index.md"};function s(l,a,o,d,p,h){return i(),e("div",null,[...a[0]||(a[0]=[r(`<h1 id="приложение" tabindex="-1">Приложение <a class="header-anchor" href="#приложение" aria-label="Permalink to &quot;Приложение&quot;">​</a></h1><p>В этом разделе собраны технические справочные материалы Antigravity Tools, включая шпаргалку по API-эндпоинтам, структуру хранения данных и описание границ экспериментальной функциональности. Когда вам нужно быстро найти конкретную техническую деталь, здесь находится ваш «словарь».</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Документ</th><th>Описание</th><th>Подходящие сценарии</th></tr></thead><tbody><tr><td><strong><a href="./endpoints/">Шпаргалка по эндпоинтам</a></strong></td><td>Обзор внешних HTTP-маршрутов: эндпоинты OpenAI/Anthropic/Gemini/MCP, режимы аутентификации и форматы заголовков</td><td>Подключение нового клиента, устранение неполадок 404/401</td></tr><tr><td><strong><a href="./storage-models/">Данные и модели</a></strong></td><td>Структура файлов аккаунтов, структура таблиц базы статистики SQLite, спецификация ключевых полей</td><td>Резервное копирование/миграция, прямой запрос к базе, устранение неполадок</td></tr><tr><td><strong><a href="./zai-boundaries/">Границы интеграции z.ai</a></strong></td><td>Список реализованных и явно нереализованных функций z.ai</td><td>Оценка возможностей z.ai, избегание неправильного использования</td></tr></tbody></table><h2 id="рекомендуемыи-путь-обучения" tabindex="-1">Рекомендуемый путь обучения <a class="header-anchor" href="#рекомендуемыи-путь-обучения" aria-label="Permalink to &quot;Рекомендуемый путь обучения&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Шпаргалка по эндпоинтам → Данные и модели → Границы интеграции z.ai</span></span>
<span class="line"><span>          ↓                     ↓                       ↓</span></span>
<span class="line"><span>   Знать какой путь вызвать   Знать где данные      Знать где границы</span></span></code></pre></div><ol><li><strong>Сначала посмотрите шпаргалку по эндпоинтам</strong>: узнайте, какие API можно вызывать, и как настроить аутентификацию</li><li><strong>Затем посмотрите «Данные и модели»</strong>: узнайте структуру хранения данных, что удобно для резервного копирования, миграции и прямого запроса к базе для устранения неполадок</li><li><strong>Наконец посмотрите «Границы интеграции z.ai»</strong>: если вы используете z.ai, эта статья поможет вам не принять «нереализованное» за «доступное»</li></ol><div class="tip custom-block"><p class="custom-block-title">Эти документы не являются «обязательными к чтению»</p><p>Приложение — это справочные материалы, а не учебник. Вам не нужно читать его от начала до конца, просто обращайтесь к нему при возникновении конкретных вопросов.</p></div><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Рекомендуется сначала завершить</p><ul><li><a href="./../start/getting-started/">Что такое Antigravity Tools</a>: создать базовую ментальную модель</li><li><a href="./../start/proxy-and-first-client/">Запуск локального прокси и подключение первого клиента</a>: выполнить базовый рабочий процесс</li></ul></div><p>Если вы ещё не выполнили базовый рабочий процесс, рекомендуется сначала завершить уроки из главы <a href="./../start/">Начало работы</a>.</p><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения чтения приложения вы можете:</p><ul><li><strong><a href="./../changelog/release-notes/">Эволюция версий</a></strong>: узнать о недавних изменениях и провести проверку перед обновлением</li><li><strong><a href="./../faq/invalid-grant/">Часто задаваемые вопросы</a></strong>: при встрече с конкретными ошибками искать ответы в главе FAQ</li><li><strong><a href="./../advanced/config/">Расширенная конфигурация</a></strong>: глубже понять горячее обновление конфигурации, стратегии планирования и другие продвинутые функции</li></ul>`,14)])])}const u=t(n,[["render",s]]);export{g as __pageData,u as default};
